/**
 * 星表数据管理与加载
 * 支持分层加载：核心亮星 -> 扩展恒星 -> 高精度星表
 */

import { DEG2RAD, RAD2DEG } from '../astronomy/math.js';
import { getBrightStars } from './brightStars.js';

// ============================================
// 数据分层配置
// ============================================

export const STAR_LAYERS = {
  core: {
    name: 'core',
    file: 'data/stars-core.bin',
    maxMagnitude: 3.0,
    count: 300,
    priority: 1
  },
  extended: {
    name: 'extended',
    file: 'data/stars-ext.bin',
    maxMagnitude: 6.0,
    count: 9000,
    priority: 2
  },
  tycho: {
    name: 'tycho',
    file: 'data/stars-tycho.bin',
    maxMagnitude: 8.0,
    count: 100000,
    priority: 3,
    optional: true
  }
};

// ============================================
// 数据加载器
// ============================================

export class StarCatalog {
  constructor() {
    this.layers = new Map();
    this.loadedLayers = new Set();
    this.loadingPromises = new Map();
    this.stars = [];
    this.nameTable = [];
    this.constellationIndex = new Map();
  }

  async loadLayer(layerConfig) {
    const { name, file, priority } = layerConfig;

    if (this.loadedLayers.has(name)) {
      return this.layers.get(name);
    }

    if (this.loadingPromises.has(name)) {
      return this.loadingPromises.get(name);
    }

    const loadPromise = this._fetchAndParse(file, layerConfig)
      .then(data => {
        this.layers.set(name, data);
        this.loadedLayers.add(name);
        this.loadingPromises.delete(name);
        this.stars = [...this.stars, ...data.stars];
        console.log(`✅ 星表层 ${name} 加载完成: ${data.stars.length} 颗恒星`);
        return data;
      })
      .catch(err => {
        console.error(`❌ 星表层 ${name} 加载失败:`, err);
        this.loadingPromises.delete(name);
        throw err;
      });

    this.loadingPromises.set(name, loadPromise);
    return loadPromise;
  }

  async loadCore() {
    return this.loadLayer(STAR_LAYERS.core);
  }

  async loadExtended() {
    return this.loadLayer(STAR_LAYERS.extended);
  }

  async loadAll() {
    await this.loadCore();
    await this.loadExtended();
    if (!STAR_LAYERS.tycho.optional) {
      await this.loadLayer(STAR_LAYERS.tycho);
    }
  }

  getStars() {
    return this.stars;
  }

  filterByMagnitude(maxMag) {
    return this.stars.filter(s => s.magnitude <= maxMag);
  }

  filterByRegion(centerRa, centerDec, radius) {
    const centerRaRad = centerRa * DEG2RAD;
    const centerDecRad = centerDec * DEG2RAD;
    const radiusRad = radius * DEG2RAD;

    return this.stars.filter(star => {
      const dRa = (star.ra - centerRa) * DEG2RAD;
      const dDec = (star.dec - centerDec) * DEG2RAD;
      const dist = Math.sqrt(
        (Math.cos(centerDecRad) * dRa) ** 2 + dDec ** 2
      );
      return dist <= radiusRad;
    });
  }

  filterByConstellation(constellationIndex) {
    return this.stars.filter(s => s.constellation === constellationIndex);
  }

  searchByName(query) {
    const lowerQuery = query.toLowerCase();
    return this.stars.filter(star => {
      if (star.name && star.name.toLowerCase().includes(lowerQuery)) return true;
      if (star.bayer && star.bayer.toLowerCase().includes(lowerQuery)) return true;
      return false;
    });
  }

  findNearest(ra, dec, maxDistance = 0.5) {
    let nearest = null;
    let minDist = Infinity;

    for (const star of this.stars) {
      const dRa = (star.ra - ra) * DEG2RAD * Math.cos(dec * DEG2RAD);
      const dDec = (star.dec - dec) * DEG2RAD;
      const dist = Math.sqrt(dRa * dRa + dDec * dDec) * RAD2DEG;

      if (dist < minDist && dist <= maxDistance) {
        minDist = dist;
        nearest = star;
      }
    }

    return nearest;
  }

  async _fetchAndParse(file, config) {
    const response = await fetch(file);
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}: ${response.statusText}`);
    }
    const buffer = await response.arrayBuffer();
    return this._parseBinary(buffer, config);
  }

  _parseBinary(buffer, config) {
    // 简化解析 - 实际使用时实现完整二进制解析
    return { stars: [], nameTable: [], count: 0, version: 1 };
  }
}

// ============================================
// 使用真实亮星数据
// ============================================

export function generateTestStars() {
  // 返回真实亮星数据
  return getBrightStars();
}
