/**
 * 获取格式化的恒星数据
 */
export function getBrightStars() {
  return BRIGHT_STARS.map(star => ({
    id: star.id,
    name: star.name,
    bayer: star.bayer,
    ra: star.ra,
    dec: star.dec,
    magnitude: star.mag,
    colorIndex: star.ci,
    spectralType: star.sp,
    constellation: star.con,
    pmRA: star.pmRA,
    pmDec: star.pmDec,
    parallax: star.parallax
  }));
}
